var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"02:17 AM <color=#ffd34c>샤레이드</color>, 혁신기업지구\\n<color=#ffd34c>임시 지휘소</color> 섬멸작전 브리핑 중","JPN":"02:17 AM <color=#ffd34c>シャレード</color>, 革新企業地区\\n<color=#ffd34c>臨時指揮所</color>殲滅作戦ブリーフィング中","ENG":"[[","TWN":"02:17 AM <color=#ffd34c>查雷德</color>, 創新企業區\\n<color=#ffd34c>臨時指揮中心</color> 殲滅戰簡報中","THA":"02:17 น. <color=#ffd34c>ชาเรด</color> เซกเตอร์ธุรกิจนวัตกรรม\\n<color=#ffd34c>ศูนย์บัญชาการชั่วคราว</color> การชี้แจงรายละเอียดคร่าวๆ ของปฏิบัติการกำจัด","VTN":"02:17 SA <color=#ffd34c>Charade</color>, Phân Bộ Kinh Doanh Sáng Tạo\\n<color=#ffd34c>Trung Tâm Chỉ Huy Tạm Thời</color> Tóm Tắt Tác Chiến Tiêu Diệt","SCN":"上午02:17<color=#ffd34c>查雷德</color>，创新企业区\\n<color=#ffd34c>临时指挥所</color>歼灭作战简报中","DEU":"02:17\xA0Uhr, <color=#ffd34c>Charade</color>, Innovationsviertel\\n<color=#ffd34c>Temporäre Zentrale</color>, Briefing der Eliminierungsoperation","FRA":"2h17 du matin,<color=#ffd34c>Charade</color>. Secteur des entreprises innovatrices\\n<color=#ffd34c>Centre de commandement temporaire</color> Briefing de l'opération Élimination"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"좋아, 친구들. 현 시간부로 관리국으로부터 섬멸작전 지시가 떨어졌다.","JPN":"よし、みんな。現時刻を持って管理局から殲滅作戦指示が下った。","ENG":"Hello friends, the Administration just green-lighted the elimination operation.","TWN":"好的，朋友們。收到來自管理局的指令。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"도시관리국의 의향에 따라 이번 건은 우리 페넥 폭스가 주관하기로 했어.","JPN":"都市管理局の希望によって、この件は我々フェネックフォックスが担当することになったぞ。","ENG":"As per City Managements’ instructions, we, Fennec Fox will be in charge this time.","TWN":"照城市管理局的意思，此次行動由我們沙狐主導。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"불만 있는 사람?","JPN":"不満ある人？","ENG":"Any objections?","TWN":"有人有意見嗎？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"네, 여기 한 명.","JPN":"はーい、あたし。","ENG":"I object.","TWN":"有，我有意見。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"왜 먼지 풀풀 날리는 구닥다리 아재가 대장 행세야? 나 이거 업계 부조리로 신고해도 돼?","JPN":"なんでこの古臭いおっさんが隊長なの？　パワハラで訴えてもいいよね？","ENG":"Why are you the boss? You’re just an old man who knows nothing. I’m going to file a complaint for this.","TWN":"為什麼是全身都灰塵的大叔當隊長？我可以跟勞工局申訴嗎？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"설마. 관리국에서 실력 좋은 뉴페이스들이 편하게 활약하라고 정한 인선이지.","JPN":"まさか。実力のある新人たちが気楽に活躍できるように管理局から決めた人選、ってわけだ。","ENG":"Hey, they chose me so that you, amazing newcomers can go wild without worries.","TWN":"別這樣，管理局的美意是要讓有能力的新面孔可以輕鬆展現實力吧。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"자질구레한 일들은 우리가 처리해 줄게. 마음껏 날뛰어 보라고.","JPN":"細かい仕事は私たちに任せて、思いっきり暴れてきな！","ENG":"I’ll take care of the miscellaneous tasks. You go ahead and have fun in the field.","TWN":"像這種雞毛蒜皮的小事我們來處理就好！你就盡情玩樂吧！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"어쩐다. 허접들이 응원해 줘 봤자 의욕은 하나도 안 나는데.","JPN":"どうかなー。雑魚たちから応援されてもぜーんぜんやる気出ないんだよなー。","ENG":"Oh well, such comment from a low critter like you don’t cheer me up at all.","TWN":"怎麼辦～面對這些傢伙一點都提不起勁～"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"드라코 씨라고 하셨죠. 말씀 좀 가려 하세요.","JPN":"ドラコさんでしたよね。口調には気をつけてください。","ENG":"Dracasia, is it? Please watch your mouth.","TWN":"你叫德拉克對吧？說話請客氣一點。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"페넥폭스 협동조합은 로터스 수복에 공헌했던 분들이라고요. 업계 선배님들께 최소한의 예의는 갖춰야죠.","JPN":"フェネックフォックスは、ロータスの修復に貢献した方々です。業界の先輩たちに最低限のマナーは守るべきでしょう。","ENG":"Fennec Fox Association contributed greatly to the Lotus recovery operation. Show some respect to the veterans.","TWN":"沙狐可是收復洛德斯的大功臣，對業界的前輩請保持禮貌。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"와, 순무가 말도 할 줄 아네.","JPN":"へえー、カブが喋ってる。","ENG":"Why, a talking turnip.","TWN":"哇，蔥會說話欸！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"누, 누가 순무라는 건데요!","JPN":"だ、誰がカブですか！","ENG":"I, I’m not a turnip!","TWN":"你…你說誰是蔥！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"몰랐어? 너 이미 SNS에 소문 쫙 퍼졌는데?","JPN":"知らないんだ。君、SNSで有名になってるよ？","ENG":"You didn’t know? It’s all over the social networks.","TWN":"你不知道喔？你現在在網路上超火欸！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"그런 꼴 당하고 잘도 얼굴을 들이미네. 관리국 직할이란 이름이 부끄럽지도 않아?","JPN":"そんな恥をかいてよくここまで来れたね。管理局の直轄ってタイトルが恥ずかしくないの？","ENG":"Shame on you. You’re supposed to be an Administration official Counter, yet here you are.","TWN":"被弄成倒栽蔥還有臉出來說話，你不覺得有愧於管理局直轄之名嗎？"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"크읏……!","JPN":"くっ……！","ENG":"Hmph...!","TWN":"唔……！"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"하하, 싸울 것 없어. 로터스를 되찾은 건 우리보다 한참 윗 기수 분들이니까.","JPN":"まあまあ、喧嘩することないさ。ロータスを取り戻したのは私たちよりも遥かに上の先輩たちだからな。","ENG":"Haha, calm down, everyone. Lotus was recovered by our seniors, not us. So it’s okay.","TWN":"哈哈～沒什麼好吵的。收復洛德斯的是比我們更厲害的人。"},"stage":{"bg":"WAREHOUSE_03","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};